import { PropsCellView } from '@semparar/design-system-app/src/atomic/fintech/Cell/Models';
import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';

type CellType = 'physicalCard' | 'virtualCard' | 'tag' | 'others';

type ItemIconDataByType = Record<
  CellType,
  Pick<PropsCellView, 'leftIcon' | 'leftIconColor' | 'bgIconColor'>
>;

export type TransactionItems = {
  descriptionColor: string;
  hourColor: string;
  iconColor: string;
  titleColor: string;
  valueColor: string;
  icon: PropsIconsNameCore;
  hour: string | undefined;
  title: string;
  type: string | undefined;
  description: string | undefined;
  value: string;
  id: number;
  cashback: number;
  percentage: string | undefined;
  resgate?: boolean;
  onPress: (...args: any[]) => Promise<any> | any;
};

export type CustomTransactionsData = {
  date: string;
  items: TransactionItems[];
};

type parent = {
  icon: PropsIconsNameCore;
  title: string;
  value: string;
  iconColor?: string;
};

export interface CashbackCellDropdownProps {
  parent: parent;
  onScroll?: () => void;
  cashbackData: CustomTransactionsData[];
  isAvailableCashback?: boolean;
}

export interface CashbackCellDropdownViewProps
  extends Omit<CashbackCellDropdownProps, 'cashbackData'> {
  isOpen: boolean;
  handleDropdown: () => void;
  formattedItems: any;
}

