import { PropsIconsNameCore, PropsTokenColorsCore } from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { TypesTagLabel } from '@semparar/design-system-app/src/atomic/molecules/TagLabel/Models';

import { mapDispatchToProps, mapStateToProps } from '..';

import { ModalizeProps } from 'react-native-modalize';
import { BlockTypes } from '../../../../redux/ducks/customers/products';
import { AnalyticsProps, ConnectProps } from '../../../../routes/Models';

export enum CardType {
  PHYSICAL = 'physical',
  VIRTUAL = 'virtual',
  TAG = 'tag',
  ADDITIONAL = 'additional',
}

export enum CardLabel {
  TAG = 'Tag',
  ACTIVATE_CARD = 'Ativar cartão',
  VIRTUAL = 'Virtual',
  PHYSICAL = 'Físico',
  BLOCKED = 'Bloqueado',
  CANCELED = 'Cancelado',
  DELIVERY_FAILED = 'Falha na entrega',
}

export type TCardUtils = {
  getTagLabelText: (item: CardLabel, blocked?: boolean) => string | undefined;
  getTagLabelTextPhysical: (item: CardLabel) => string | undefined;
  failedOrCancelled: (item: CardLabel, blocked?: boolean, blockedTypes?: CardLabel[]) => boolean;
  getTagLabelType: (item: CardLabel, blocked?: boolean) => TypesTagLabel;
  getIconName: (item: CardLabel) => PropsIconsNameCore;
  getColor: (item: CardLabel, blocked?: boolean) => PropsTokenColorsCore;
  getDescription: (item: Card, hideNumberCard?: boolean) => string;
};

export type handleCardDetailProps = {
  type: CardLabel;
  cardNumber: string;
  physicalCode?: number;
  analytics: AnalyticsProps;
  isAdditionalCard?: boolean;
};

export interface MyCardsViewProps {
  isAdditionalCardFlowEnabled: boolean;
  canRequestAdditionalCard: boolean;
  physicalCard: Card[];
  additionalCards: Card[];
  cardsToShow: CardType[];
  handleCardDetail: (data: handleCardDetailProps) => void;
  navigateToAdditionalCard: () => void;
  isLoading: boolean;
  modalizeRef: ModalizeProps;
  handleCreateVirtualCardPress: () => void;
  blockedPhysicalCard: Card | undefined;
  cardUtils: TCardUtils;
  setModalVisible: React.Dispatch<React.SetStateAction<boolean>>;
  virtualCardStatus: {
    hasVirtualCard: boolean;
    isBlocked: boolean;
    tagText: string;
    tagType: TypesTagLabel;
    onPress: () => void;
    description: string;
  };
  widthSkeleton: number;
}

export interface MyCardsRefProps extends Omit<PropsModalizeRef, 'open'> {
  open(type?: CardType[]): void;
  openCreateVirtualCardModal(): void;
}

export interface MyCardsProps
  extends ConnectProps<typeof mapStateToProps, typeof mapDispatchToProps> {}

export interface CardsMap {
  virtual: Card[];
  physical: Card[];
  additional: Card[];
  tag: Card[];
}

export interface Card {
  id: number;
  numberCard: string;
  name: string;
  bloqueio: boolean;
  typeCard: CardLabel;
  tipoBloqueio: BlockTypes;
  motivoCancelamento: string;
  Embossado: boolean;
  Titular?: boolean;
  Virtual?: boolean;
}

