   254→
   255→    if (activatedCard) {
   256→      return [activatedCard];
   257→    }
   258→
   259→    if (canceledCard && cardToBeActivated) {
   260→      return [canceledCard, cardToBeActivated];
   261→    }
   262→
   263→    if (cardToBeActivated) {
   264→      return physicalCards;
   265→    }
   266→
   267→    if (hasTwoCancelled) {
   268→      return [physicalCards[0]];
   269→    }
   270→
   271→    if (canceledCard) {
   272→      return physicalCards?.filter(
   273→        (card) =>
   274→          card.typeCard !== CardLabel.DELIVERY_FAILED && card.typeCard !== CardLabel.CANCELED
   275→      );
   276→    }
   277→
   278→    return physicalCards?.filter((card) => card.typeCard !== CardLabel.DELIVERY_FAILED);
