import { NavigationProp, useNavigation } from '@react-navigation/native';
import { BackDropBottom, Box } from '@semparar/design-system-app';
import { ModalTwoButton } from '@semparar/design-system-app/fintech';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import moment from 'moment';
import React, {
  forwardRef,
  ForwardRefRenderFunction,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react';
import { Dimensions, useWindowDimensions } from 'react-native';
import { connect, useSelector } from 'react-redux';
import { bindActionCreators, Dispatch } from 'redux';
import { eventSelectContent } from '~/constants/functions';

import { useAdditionalCardsEnabled } from '../../../hooks/useSelectors';
import { ProductCard, productsAction } from '../../../redux/ducks/customers/products';
import { virtualCardActions } from '../../../redux/ducks/virtualCard';
import { AppReducers } from '../../../redux/reducers/Models';
import { AnalyticsProps, PropsRootStack } from '../../../routes/Models';
import { NumberCardVirtualRecurrentRouteParams } from '../../../screens/Cards/DetailVirtualCardRecurrent/Models';
import { debounceModal } from '../../../utils/debounceModal';
import { capitalizeEachWord } from '../../../utils/functions';
import { getIsCanceledCard } from '../../../utils/getIsCanceledCard';

import LoadingModal from '../../molecules/LoadingModal';
import Success from '../../templates/Success';
import ApiError from '../ApiError';
import ConfirmReceivedCard from '../ConfirmReceivedCard';
import {
  Card,
  CardLabel,
  CardsMap,
  CardType,
  MyCardsProps,
  MyCardsRefProps,
  MyCardsViewProps,
  TCardUtils,
} from './Models';
import MyCardsView from './view';

const HEIGHT_DIMENSION = Dimensions.get('screen').height;
const DEFAULT_CARDS_TYPE_TO_SHOW = [
  CardType.ADDITIONAL,
  CardType.PHYSICAL,
  CardType.TAG,
  CardType.VIRTUAL,
];

const MyCards: ForwardRefRenderFunction<MyCardsRefProps, MyCardsProps> = (
  {
    productsReducer,
    putVirtualCard,
    customerReducer,
    accountReducer,
    cleanVirtualCard,
    productRequest,
    virtualCardReducer,
  },
  ref
) => {
  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
  const { hasReachedMaxAdditionalCards } = useAdditionalCardsEnabled();

  const [uiState, setUiState] = useState({
    isModalVisible: false,
    activeCardNumber: null as string | null,
    activeCardTrigger: 0,
    newCardNumber: false,
    cardsToShow: DEFAULT_CARDS_TYPE_TO_SHOW as CardType[],
  });
  const isAdditionalCardFlowEnabled = useSelector(
    ({ featuresReducer }: AppReducers) =>
      !!(
        'appFintechShowAdditionalCardFlow' in featuresReducer &&
        featuresReducer.appFintechShowAdditionalCardFlow
      )
  );

  const { width } = useWindowDimensions();

  const modalizeRef = useRef<PropsModalizeRef>(null);
  const refConfirmedReceivedCard = useRef<PropsModalizeRef>(null);

  const handleCreateVirtualCardPress = useCallback(() => {
    modalizeRef?.current?.close?.();
    eventSelectContent({
      content_type: 'cta',
      content_id: 'criar_cartao_virtual',
      location_1: 'autosservico',
      location_2: 'spmais',
      location_3: 'cartao_virtual_ativar',
    });
    debounceModal(() => setUiState((prev) => ({ ...prev, isModalVisible: true })));
  }, []);

  useImperativeHandle(
    ref,
    () => ({
      open: (type) => {
        setUiState((prev) => ({ ...prev, cardsToShow: type || DEFAULT_CARDS_TYPE_TO_SHOW }));
        modalizeRef.current?.open?.();
      },
      close: () => {
        modalizeRef.current?.close?.();
      },
      openCreateVirtualCardModal: () => {
        handleCreateVirtualCardPress();
      },
    }),
    [handleCreateVirtualCardPress]
  );

  useEffect(() => {
    if (uiState.activeCardNumber && uiState.activeCardTrigger > 0) {
      refConfirmedReceivedCard.current?.open?.();
    }
  }, [uiState.activeCardTrigger]);

  const cards = productsReducer?.data?.[0]?.Cartoes;

  const lastCards =
    cards?.length >= 2
      ? cards?.sort((a, b) => {
          if (moment(a.DataAberturaCartao).isAfter(b.DataAberturaCartao)) {
            return -1;
          }
          if (moment(a.DataAberturaCartao).isBefore(b.DataAberturaCartao)) {
            return 1;
          }
          if (moment(a.DataAtivacao).isAfter(b.DataAtivacao)) {
            return -1;
          }
          if (moment(a.DataAtivacao).isBefore(b.DataAtivacao)) {
            return 1;
          }
          return 0;
        })
      : cards;

  const getCardTypeLabel = (obj: ProductCard) => {
    if (accountReducer?.card?.cardNumber?.endsWith(obj.NrCartao.slice(-4))) {
      return CardLabel.TAG;
    }

    if (obj.TipoBloqueio === 'XW') {
      return CardLabel.ACTIVATE_CARD;
    }

    const isDeliveryFailed =
      (obj.TipoBloqueio === 'VW' && obj.MotivoCancelamento === '112') ||
      (obj.TipoBloqueio === 'XS' && obj.MotivoCancelamento === '993');

    if (isDeliveryFailed) {
      return CardLabel.DELIVERY_FAILED;
    }

    const isCancelled =
      obj.Status?.toLowerCase() === 'cancelado' ||
      (obj.Bloqueio &&
        getIsCanceledCard({
          cancellationReason: obj.MotivoCancelamento,
          blockType: obj.TipoBloqueio,
        }));

    if (isCancelled) {
      return CardLabel.CANCELED;
    }

    if (obj.MotivoCancelamento !== '356' && obj.Bloqueio && !obj.Virtual && !isCancelled) {
      return CardLabel.BLOCKED;
    }

    return obj.Virtual ? CardLabel.VIRTUAL : CardLabel.PHYSICAL;
  };

  const cardsMap: CardsMap = useMemo(
    () =>
      lastCards?.reduce(
        (acc, obj, index) => {
          const typeCard = getCardTypeLabel(obj);
          const payload: Card = {
            id: index,
            numberCard: obj.NrCartao.slice(-4),
            name: obj.NomePortador,
            bloqueio: obj.Bloqueio,
            typeCard,
            tipoBloqueio: obj.TipoBloqueio,
            motivoCancelamento: obj.MotivoCancelamento,
            Embossado: obj.Embossado,
          };

          if (
            obj.Virtual &&
            typeCard !== CardLabel.TAG &&
            uiState.cardsToShow.includes(CardType.VIRTUAL)
          ) {
            acc.virtual.push(payload);
            return acc;
          }
          if (CardLabel.TAG === typeCard && uiState.cardsToShow.includes(CardType.TAG)) {
            acc.tag.push(payload);
            return acc;
          }

          if (obj.Titular && uiState.cardsToShow.includes(CardType.PHYSICAL)) {
            acc.physical.push(payload);
            return acc;
          }

          if (!obj.Titular && !obj.Virtual && uiState.cardsToShow.includes(CardType.ADDITIONAL)) {
            acc.additional.push(payload);
          }
          return acc;
        },
        {
          [CardType.PHYSICAL]: [],
          [CardType.VIRTUAL]: [],
          [CardType.ADDITIONAL]: [],
          [CardType.TAG]: [],
        } as Record<CardType, Card[]>
      ),
    [productsReducer?.data?.[0]?.Cartoes, uiState.cardsToShow]
  );

  const filterPhysicalCards = useMemo(() => {
    const physicalCards =
      cardsMap?.physical?.length > 2
        ? [cardsMap?.physical[0], cardsMap?.physical[1]]
        : cardsMap?.physical;

    if (!physicalCards?.length) {
      return [];
    }

    const activatedCard = physicalCards?.find((card) => !card.bloqueio);
    const cardToBeActivated = physicalCards?.find(
      (card) => card.typeCard === CardLabel.ACTIVATE_CARD
    );
    const canceledCard = physicalCards?.find((card) => card.typeCard === CardLabel.CANCELED);
    const failedToDeliver = physicalCards?.find(
      (card) => card.typeCard === CardLabel.DELIVERY_FAILED
    );
    const hasTwoCancelled = physicalCards?.every((card) => card.typeCard === CardLabel.CANCELED);

    if (failedToDeliver && physicalCards?.length < 2) {
      return [failedToDeliver];
    }

    if (activatedCard) {
      return [activatedCard];
    }

    if (canceledCard && cardToBeActivated) {
      return [canceledCard, cardToBeActivated];
    }

    if (cardToBeActivated) {
      return physicalCards;
    }

    if (hasTwoCancelled) {
      return [physicalCards[0]];
    }

    if (canceledCard) {
      return physicalCards?.filter(
        (card) =>
          card.typeCard !== CardLabel.DELIVERY_FAILED && card.typeCard !== CardLabel.CANCELED
      );
    }

    return physicalCards?.filter((card) => card.typeCard !== CardLabel.DELIVERY_FAILED);
  }, [cardsMap]);

  const physicalCard = filterPhysicalCards?.filter((pCard) => pCard?.id !== undefined);

  const handleCardDetail: MyCardsViewProps['handleCardDetail'] = ({
    type,
    cardNumber,
    physicalCode,
    analytics,
    isAdditionalCard,
  }) => {
    switch (type) {
      case CardLabel.VIRTUAL:
        navigation.navigate('DetailVirtualCardRecurrent', {
          numberCard: cardNumber,
          analytics,
        } as unknown as NumberCardVirtualRecurrentRouteParams & AnalyticsProps);
        modalizeRef?.current?.close?.();
        break;
      case CardLabel.TAG:
        handleTagDetail(cardNumber, analytics);
        break;
      case CardLabel.ACTIVATE_CARD:
        modalizeRef?.current?.close?.();
        debounceModal(() => setUiState((prev) => ({ 
          ...prev, 
          activeCardNumber: cardNumber,
          activeCardTrigger: prev.activeCardTrigger + 1
        })));
        break;
      default:
        navigation.navigate('DetailPhysicalCard', {
          numberCard: cardNumber,
          physicalCode,
          analytics,
          isAdditionalCard,
        });
        modalizeRef?.current?.close?.();
        break;
    }
  };

  const handleTagDetail = (numberCard: string, analytics?: AnalyticsProps) => {
    navigation.navigate('TagDetail', {
      numberCard,
      analytics,
    } as unknown as NumberCardVirtualRecurrentRouteParams & AnalyticsProps);
  };

  const getProducts = useCallback(() => {
    setTimeout(() => {
      productRequest(false, ({ statusCode }) => {
        if (statusCode === 200) {
          setUiState((prev) => ({ ...prev, newCardNumber: true }));
        }
        if (statusCode === 504) {
          getProducts();
        }
      });
    }, 1000);
  }, []);

  const handleCreateVirtualCard = () => {
    setUiState((prev) => ({ ...prev, isModalVisible: false }));
    putVirtualCard({ CPF: customerReducer.document, Conta: productsReducer.data[0]?.Conta }, () =>
      getProducts()
    );
  };

  const handleGoToCardDetail = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'acesse_cartao_virtual',
      location_1: 'autosservico',
      location_2: 'spmais',
      location_3: 'cartao_virtual_ativar_sucesso',
    });
    const cardNumberNavigation = productsReducer?.data?.[0]?.Cartoes?.find((item) => {
      return item.NrCartao.endsWith(virtualCardReducer.cardNumber.slice(-4));
    });

    if (!cardNumberNavigation) {
      return;
    }

    navigation.navigate('DetailVirtualCardRecurrent', {
      numberCard: cardNumberNavigation?.NrCartao?.substring(
        cardNumberNavigation.NrCartao.length,
        12
      ),
      analytics: {
        screen_name: 'spmais',
        screen_class: 'cartao_virtual_ativar_sucesso',
        screen_bussines: 'autosservico',
        screen_info: {
          location_1: 'autosservico',
          location_2: 'spmais',
          location_3: 'cartao_virtual_ativar_sucesso',
        },
      },
    });

    setUiState((prev) => ({ ...prev, newCardNumber: false }));
  };

  const handleNavigateToLiveness = () => {
    setUiState((prev) => ({ ...prev, activeCardNumber: null }));
    refConfirmedReceivedCard.current?.close?.();
    if (uiState.activeCardNumber) {
      navigation.navigate('CardValidation', {
        lastFourNumbers: uiState.activeCardNumber,
        from: 'fintechHome',
        analytics: {
          screen_name: 'spmais',
          screen_class: 'meus_cartoes',
          screen_bussines: 'autosservico',
          screen_info: {
            location_1: 'autosservico',
            location_2: 'spmais',
            location_3: 'meus_cartoes',
          },
        },
      });
    }
  };

  const handleCloseConfirmReceivedCard = () => {
    setUiState((prev) => ({ ...prev, activeCardNumber: null }));
    refConfirmedReceivedCard.current?.close?.();
  };

  const handleCardError = useCallback(() => {
    getProducts();
    cleanVirtualCard();
  }, []);

  const modalHeight = useMemo(() => {
    const height = cards?.length > 6 ? 0.65 : cards?.length > 3 ? 0.55 : 0.4;

    return Math.round(HEIGHT_DIMENSION * height);
  }, [cards?.length]);

  const CardUtils: TCardUtils = {
    getTagLabelText: (item: CardLabel, blocked = false) => {
      if (blocked) {
        return 'Bloqueado';
      }

      if (item === CardLabel.VIRTUAL) {
        return undefined;
      }

      return item;
    },
    getTagLabelTextPhysical: (item: CardLabel) => {
      if ([CardLabel.PHYSICAL, CardLabel.VIRTUAL, CardLabel.TAG].includes(item)) {
        return undefined;
      }

      if (item === CardLabel.ACTIVATE_CARD) {
        return 'Ativar';
      }

      return item;
    },
    failedOrCancelled: (
      item: CardLabel,
      blocked = false,
      blockedTypes = [CardLabel.CANCELED, CardLabel.BLOCKED, CardLabel.DELIVERY_FAILED]
    ) => blockedTypes.includes(item) || blocked,
    getTagLabelType: (item: CardLabel, blocked = false) =>
      CardUtils.failedOrCancelled(item) || blocked ? 'error' : 'highlight',
    getIconName: (item: CardLabel) =>
      CardUtils.failedOrCancelled(item) ? 'icon-card-block' : 'icon-card',
    getColor: (item: CardLabel, blocked = false) =>
      CardUtils.failedOrCancelled(item) || blocked ? 'INTENSE_COLOR_02' : 'BRAND_COMPLEMENT_01',
    getDescription: (item: Card, hideNumberCard = false) =>
      `${capitalizeEachWord(item?.name)} ${
        item?.typeCard !== 'Ativar cartão' && !hideNumberCard ? `- ${item?.numberCard}` : ''
      }`,
  };

  const getVirtualCardStatus = useCallback(() => {
    if (cardsMap?.virtual?.length === 0) {
      return {
        hasVirtualCard: false,
        isBlocked: false,
        tagText: 'Ativar',
        tagType: 'highlight' as const,
        onPress: handleCreateVirtualCardPress,
        description: '',
      };
    }
    if (cardsMap?.virtual?.some((card) => card.bloqueio)) {
      return {
        hasVirtualCard: true,
        isBlocked: true,
        tagText: 'Bloqueado',
        tagType: 'error' as const,
        onPress: () => {
          const blockedCard = cardsMap?.virtual?.find((card) => card.bloqueio);
          if (blockedCard) {
            handleCardDetail({
              type: CardLabel.VIRTUAL,
              cardNumber: blockedCard.numberCard,
              analytics: {
                analytics: {
                  screen_name: 'spmais',
                  screen_class: 'meus_cartoes',
                  screen_bussines: 'autosservico',
                  screen_info: {
                    location_1: 'autosservico',
                    location_2: 'spmais',
                    location_3: 'meus_cartoes',
                  },
                },
              },
            });
          }
        },
        description: CardUtils.getDescription(cardsMap?.virtual?.[0]),
      };
    }
    return {
      hasVirtualCard: true,
      isBlocked: false,
      tagText: '',
      tagType: 'neutral' as const,
      onPress: () => {
        const activeCard = cardsMap?.virtual?.[0];
        if (activeCard) {
          handleCardDetail({
            type: CardLabel.VIRTUAL,
            cardNumber: activeCard.numberCard,
            analytics: {
              analytics: {
                screen_name: 'spmais',
                screen_class: 'meus_cartoes',
                screen_bussines: 'autosservico',
                screen_info: {
                  location_1: 'autosservico',
                  location_2: 'spmais',
                  location_3: 'meus_cartoes',
                },
              },
            },
          });
        }
      },
      description: CardUtils.getDescription(cardsMap?.virtual?.[0]),
    };
  }, [productsReducer?.data, handleCardDetail, handleCreateVirtualCardPress]);

  const virtualCardStatus = getVirtualCardStatus();

  const viewCards = useMemo(() => {
    if (virtualCardReducer.isLoading || productsReducer.isLoading) {
      return <LoadingModal text="Aguarde..." />;
    }

    if (uiState.newCardNumber) {
      return (
        <Box height="100%" width={width} index={999}>
          <Success
            onPress={() => {
              handleGoToCardDetail();
            }}
            buttonProps={{ text: 'Acesse seu cartão virtual' }}
            title="Seu cartão virtual foi criado"
            subTitle="Para suas comprar online com mais segurança o CVV muda automaticamente a cada 1h."
          />
        </Box>
      );
    }

    if (virtualCardReducer?.isError && cardsMap?.virtual?.length === 0) {
      return (
        <Box height="100%" position="absolute" width={width} index={999}>
          <ApiError onPress={handleCardError} isLoading={virtualCardReducer.isLoading} />
        </Box>
      );
    }

    const navigateToAdditionalCard = () => {
      modalizeRef.current?.close?.();
      navigation.navigate('AdditionalCardInstructions');
    };

    return (
      <>
        <ConfirmReceivedCard
          refConfirmedReceivedCard={refConfirmedReceivedCard as PropsModalizeRef}
          onPressFirstButtonConfirmReceivedCard={handleNavigateToLiveness}
          onPressSecondButtonConfirmReceivedCard={handleCloseConfirmReceivedCard}
        />
        <ModalTwoButton
          title="Deseja criar seu cartão virtual?"
          typeButtonSecondary="secundarySmall"
          typeButtonPrimary="primarySmall"
          visible={uiState.isModalVisible}
          textButtonPrimary="Sim"
          textButtonSecondary="Não"
          onClose={() => setUiState((prev) => ({ ...prev, isModalVisible: false }))}
          onPressPrimaryButton={handleCreateVirtualCard}
          onPressSecondaryButton={() => setUiState((prev) => ({ ...prev, isModalVisible: false }))}
        />
        <BackDropBottom
          modalizeRef={modalizeRef}
          modalHeight={modalHeight}
          HeaderComponent={<Box />}
        >
          <MyCardsView
            handleCardDetail={handleCardDetail}
            physicalCard={physicalCard}
            additionalCards={cardsMap?.additional}
            cardsToShow={uiState.cardsToShow}
            setModalVisible={(value) => {
              const newValue = typeof value === 'function' ? value(uiState.isModalVisible) : value;
              setUiState((prev) => ({ ...prev, isModalVisible: newValue }));
            }}
            canRequestAdditionalCard={!hasReachedMaxAdditionalCards}
            navigateToAdditionalCard={navigateToAdditionalCard}
            isLoading={
              productsReducer.isLoading ||
              virtualCardReducer.isLoading ||
              productsReducer.isLoadingFromHome
            }
            cardUtils={CardUtils}
            virtualCardStatus={virtualCardStatus}
            isAdditionalCardFlowEnabled={isAdditionalCardFlowEnabled}
            widthSkeleton={width}
          />
        </BackDropBottom>
      </>
    );
  }, [
    productsReducer,
    uiState,
    cardsMap,
    virtualCardReducer,
    filterPhysicalCards,
    handleCardError,
    handleCreateVirtualCardPress,
    width,
  ]);

  return viewCards;
};

export const mapStateToProps = ({
  productsReducer,
  customerReducer,
  virtualCardReducer,
  accountReducer,
}: AppReducers) => ({
  productsReducer,
  customerReducer,
  virtualCardReducer,
  accountReducer,
});

export const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators(
    {
      ...productsAction,
      ...virtualCardActions,
    },
    dispatch
  );
};

const MyCardsWithRef = forwardRef(MyCards);

const UnconnectedMyCards = MyCards;
;

export default connect(mapStateToProps, mapDispatchToProps, null, {
  forwardRef: true,
})(MyCardsWithRef);

