import { Alert, Box, Button, CardActivity, Skeleton } from '@semparar/design-system-app';
import React, { FC } from 'react';
import { ScrollView } from 'react-native';
import { eventSelectContent } from '~/constants/functions';

import ButtonMyCards from '../../molecules/ButtonMyCards';
import { CardLabel, CardType, handleCardDetailProps, MyCardsViewProps } from './Models';
import { FlatList } from 'react-native-gesture-handler';

const LineSeparator = () => <Box width="100%" height={1} bgColor="BRAND_COMPLEMENT_05" />;

const MyCardsView: FC<MyCardsViewProps> = ({
  physicalCard,
  canRequestAdditionalCard,
  handleCardDetail,
  additionalCards,
  navigateToAdditionalCard,
  isLoading,
  cardsToShow,
  cardUtils,
  virtualCardStatus,
  isAdditionalCardFlowEnabled,
  widthSkeleton,
}) => {
  const showLimitMessageAtTop = () => {
    if (canRequestAdditionalCard) {
      return null;
    }
    return (
      <Alert
        label="Você atingiu o limite de cartões adicionais."
        type="highlight"
        hasButton={false}
        disableButton
        numberOfLines={2}
      />
    );
  };
  const lineSeparator = () => <LineSeparator />;

  const showRequestAdditionalCard = () => {
    if (!cardsToShow.includes(CardType.ADDITIONAL)) {
      return null;
    }
    if (canRequestAdditionalCard) {
      return (
        <Button
          onPress={navigateToAdditionalCard}
          width="100%"
          icon="icon-more"
          type="ghostMedium"
          text="Pedir cartão adicional"
        />
      );
    }
  };

  if (isLoading) {
    return (
      <Box width="100%" mt="smaller">
        <LineSeparator />
        <Skeleton
          testID="my-cards-list-loading"
          height={60}
          width={widthSkeleton - 48}
          mt="quark"
          mb="quark"
        />
        <LineSeparator />
      </Box>
    );
  }

  return (
    <>
      <ScrollView>
        <Box flex={1} justify="space-between">
          <Box width="100%">
            {isAdditionalCardFlowEnabled && showLimitMessageAtTop()}
            {physicalCard?.length > 0 ? (
              <FlatList
                keyExtractor={(item) => String(item?.id)}
                data={physicalCard}
                ItemSeparatorComponent={lineSeparator}
                renderItem={({ item }) => {
                  const failedOrCancelled = cardUtils.failedOrCancelled(item?.typeCard);
                  return (
                    <CardActivity
                      disabled={item?.typeCard === 'Ativar cartão' && !item.Embossado}
                      title="Cartão titular"
                      titleColor={failedOrCancelled ? 'BRAND_COMPLEMENT_02' : 'BRAND_COMPLEMENT_01'}
                      showIcon
                      showBgIcon={false}
                      hideBorder
                      description={cardUtils.getDescription(item)}
                      showTagLabel={!!cardUtils.getTagLabelTextPhysical(item?.typeCard)}
                      typeTagLabel={cardUtils.getTagLabelType(item?.typeCard)}
                      textTagLabel={cardUtils.getTagLabelTextPhysical(item?.typeCard)}
                      icon={cardUtils.getIconName(item?.typeCard)}
                      iconRight="icon-next"
                      bgColor="BRAND_COMPLEMENT_01"
                      onPress={() => {
                        eventSelectContent({
                          content_type: 'cta',
                          content_id: 'cartao_fisico',
                          location_1: 'autosservico',
                          location_2: 'spmais',
                          location_3: 'meus_cartoes',
                        });
                        handleCardDetail({
                          type: item.typeCard,
                          cardNumber: item.numberCard,
                          physicalCode: 0,
                          analytics: {
                            screen_name: 'spmais',
                            screen_class: 'meus_cartoes',
                            screen_bussines: 'autosservico',
                            screen_info: {
                              location_1: 'autosservico',
                              location_2: 'spmais',
                              location_3: 'meus_cartoes',
                            },
                          },
                        });
                      }}
                    />
                  );
                }}
              />
            ) : null}

            {cardsToShow.includes(CardType.VIRTUAL) && (
              <>
                <LineSeparator />
                <CardActivity
                  title="Cartão virtual"
                  showIcon
                  showBgIcon={false}
                  hideBorder
                  description={virtualCardStatus.description}
                  showTagLabel={!!virtualCardStatus.tagText}
                  typeTagLabel={virtualCardStatus.tagType}
                  textTagLabel={virtualCardStatus.tagText}
                  icon="icon-card-approximation"
                  iconRight="icon-next"
                  bgColor="BRAND_COMPLEMENT_01"
                  onPress={virtualCardStatus.onPress}
                />
                {additionalCards?.length > 0 && <LineSeparator />}
              </>
            )}

            {isAdditionalCardFlowEnabled && additionalCards?.length > 0 && (
              <>
                <FlatList
                  keyExtractor={(item) => `${item.name}-${item.numberCard}`}
                  data={additionalCards}
                  ItemSeparatorComponent={lineSeparator}
                  renderItem={({ item }) => {
                    return (
                      <CardActivity
                        title="Cartão adicional"
                        disabled={!item.Embossado}
                        showIcon
                        showBgIcon={false}
                        hideBorder
                        description={cardUtils.getDescription(item, item.bloqueio)}
                        showTagLabel={!!cardUtils.getTagLabelTextPhysical(item?.typeCard)}
                        typeTagLabel={cardUtils.getTagLabelType(item?.typeCard)}
                        textTagLabel={cardUtils.getTagLabelTextPhysical(item?.typeCard)}
                        icon="icon-card-more"
                        iconRight="icon-next"
                        bgColor="BRAND_COMPLEMENT_01"
                        onPress={() => {
                          eventSelectContent({
                            content_type: 'cta',
                            content_id: 'cartao_adicional',
                            location_1: 'autosservico',
                            location_2: 'spmais',
                            location_3: 'meus_cartoes',
                          });
                          handleCardDetail({
                            type: item.typeCard,
                            cardNumber: item.numberCard,
                            isAdditionalCard: true,
                            analytics: {
                              screen_name: 'spmais',
                              screen_class: 'meus_cartoes',
                              screen_bussines: 'autosservico',
                              screen_info: {
                                location_1: 'autosservico',
                                location_2: 'spmais',
                                location_3: 'meus_cartoes',
                              },
                            },
                          });
                        }}
                      />
                    );
                  }}
                />
                <LineSeparator />
              </>
            )}
            {isAdditionalCardFlowEnabled && (
              <Box align="center" width="100%" justify="flex-end" mt="xs">
                {showRequestAdditionalCard()}
              </Box>
            )}
          </Box>
        </Box>
      </ScrollView>
    </>
  );
};

export default MyCardsView;

